const all = $input.all().map(i => i.json);
const date = all[0]?.date || 'unknown';

let html = `<div style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;max-width:640px;margin:0 auto;padding:24px;">`;
html += `<h1 style="font-size:22px;color:#1a1a1a;margin-bottom:4px;">📄 HF Daily Papers — ${date}</h1>`;
html += `<p style="color:#6b7280;font-size:14px;margin-bottom:20px;">오늘의 인기 논문 Top ${all.length}편</p>`;

for (let i = 0; i < all.length; i++) {
  const p = all[i];
  if (!p.paper_id) continue;
  html += `<div style="margin-bottom:16px;padding:14px 16px;border:1px solid #e5e7eb;border-radius:10px;">`;
  html += `<div style="font-size:15px;font-weight:600;"><a href="${p.url}" style="color:#6c2bd9;text-decoration:none;">${i+1}. ${p.title}</a></div>`;
  html += `<div style="font-size:12px;color:#6b7280;margin-top:4px;">⬆️ ${p.upvotes} upvotes${p.authors ? ' · ' + p.authors : ''}</div>`;
  html += `</div>`;
}

html += `<hr style="border:none;border-top:1px solid #e5e7eb;margin:20px 0;">`;
html += `<p style="color:#9ca3af;font-size:12px;">Powered by <a href="https://www.upstage.ai" style="color:#6c2bd9;">Upstage</a> · <a href="https://huggingface.co/papers" style="color:#6c2bd9;">HuggingFace Daily Papers</a></p>`;
html += `</div>`;

return [{ json: {
  date,
  subject: `📄 HF Daily Papers — ${date} (${all.length}편)`,
  html,
  count: all.length
} }];

// Get the most recent date that likely has papers
// HF Daily Papers updates on US time, so:
// - If it's before ~10am UTC, yesterday's papers are the latest
// - We'll try today first, then yesterday, then 2 days ago
const now = new Date();
const dates = [];
for (let i = 0; i < 3; i++) {
  const d = new Date(now);
  d.setDate(d.getDate() - i);
  dates.push(d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0'));
}
return [{ json: { dates: dates } }];

// Pick the first non-empty response from today or yesterday
const items = $input.all().map(i => i.json);
const dates = items[0]?.dates || $item(0)?.$node['Prepare Dates']?.json?.dates || [];

let papers = [];
let usedDate = 'unknown';

for (const item of items) {
  let arr = [];
  try {
    if (Array.isArray(item)) arr = item;
    else if (item.body && Array.isArray(item.body)) arr = item.body;
    else if (typeof item === 'string') arr = JSON.parse(item);
    else if (typeof item.body === 'string' && item.body.startsWith('[')) arr = JSON.parse(item.body);
    else if (item.data && Array.isArray(item.data)) arr = item.data;
    // Check if the item itself has paper data (parsed array response)
    else if (item.paper) arr = [item];
  } catch (e) {}

  if (arr.length > papers.length) {
    papers = arr;
  }
}

if (papers.length === 0) {
  return [{ json: { date: dates[0] || usedDate, paper_id: '', title: 'No papers available', url: '#', upvotes: 0 } }];
}

// Determine which date was used
const firstPaper = papers[0];
usedDate = dates[0] || 'unknown'; // approximate

papers.sort((a,b) => (b.paper?.upvotes||0) - (a.paper?.upvotes||0));
const top = papers.slice(0, 10);
return top.map(p => ({
  json: {
    date: usedDate,
    paper_id: p.paper?.id || '',
    title: p.paper?.title || 'Untitled',
    url: `https://huggingface.co/papers/${p.paper?.id}`,
    upvotes: p.paper?.upvotes || 0,
    authors: (p.paper?.authors || []).map(a => a.name || a.user || '').filter(Boolean).slice(0,3).join(', ')
  }
}));
